firmware_template.source:
#include "spi_display.h"
#include <SPI.h>
#include <Adafruit_GFX.h>
static Adafruit_ILI9341 tft(15, 2, 4);
void tft_setup() {
  tft.begin();
  tft.setRotation(1);
  tft.fillScreen(ILI9341_BLACK);
  Serial.println("[tft] OK 320x240");
}
void tft_clear(uint16_t c) { tft.fillScreen(c); }
void tft_text(int x, int y, const char* t, uint16_t c, int s) {
  tft.setCursor(x, y); tft.setTextColor(c); tft.setTextSize(s); tft.print(t);
}
void tft_rect(int x, int y, int w, int h, uint16_t c) { tft.drawRect(x,y,w,h,c); }
void tft_fill_rect(int x, int y, int w, int h, uint16_t c) { tft.fillRect(x,y,w,h,c); }
void tft_line(int x0, int y0, int x1, int y1, uint16_t c) { tft.drawLine(x0,y0,x1,y1,c); }
